@app.route('/ver_evidencia_convertido/<path:filename>')
@login_required
def ver_evidencia_convertido(filename):
    full_path = safe_join(CONVERTED_FOLDER, filename)
    if not full_path or not os.path.isfile(full_path):
        abort(404)
    return send_file(full_path, mimetype='application/pdf', as_attachment=False, download_name=filename, conditional=True)



# =========================
# Vista de archivos
# =========================
# Carpeta donde guardas PDFs convertidos
CONVERTED_FOLDER = os.path.join(app.root_path, "static", "converted")
os.makedirs(CONVERTED_FOLDER, exist_ok=True)

def _find_soffice():
    """
    Encuentra el ejecutable de LibreOffice (soffice).
    - En Mac suele estar dentro de /Applications/LibreOffice.app/...
    - En Linux/Windows normalmente basta con 'soffice' en PATH.
    """
    # 1) Si está en PATH
    p = shutil.which("soffice")
    if p:
        return p

    # 2) Rutas típicas en macOS
    mac_candidates = [
        "/Applications/LibreOffice.app/Contents/MacOS/soffice",
        "/Applications/LibreOffice.app/Contents/MacOS/soffice.bin",
    ]
    for c in mac_candidates:
        if os.path.exists(c):
            return c

    return None

def ensure_pdf_from_office(filename: str) -> str | None:
    """
    Convierte .doc/.docx/.xls/.xlsx a PDF usando LibreOffice headless.
    Retorna el nombre del PDF (archivo en CONVERTED_FOLDER) o None si falla.
    """
    if not filename:
        return None

    # Seguridad: solo nombre base, no rutas
    filename = os.path.basename(filename)
    src_path = os.path.join(app.config["UPLOAD_FOLDER"], filename)

    if not os.path.isfile(src_path):
        return None

    ext = os.path.splitext(filename)[1].lower()
    if ext not in {".doc", ".docx", ".xls", ".xlsx"}:
        return None

    # Nombre PDF destino
    base = os.path.splitext(filename)[0]
    out_pdf_name = secure_filename(base) + ".pdf"
    out_pdf_path = os.path.join(CONVERTED_FOLDER, out_pdf_name)

    # Cache: si ya existe y es más nuevo que el origen, no reconvertir
    try:
        if os.path.isfile(out_pdf_path):
            if os.path.getmtime(out_pdf_path) >= os.path.getmtime(src_path):
                return out_pdf_name
    except Exception:
        pass

    soffice = _find_soffice()
    if not soffice:
        # No hay LibreOffice disponible
        return None

    # Ejecuta conversión
    try:
        cmd = [
            soffice,
            "--headless",
            "--nologo",
            "--nolockcheck",
            "--nodefault",
            "--nofirststartwizard",
            "--convert-to", "pdf",
            "--outdir", CONVERTED_FOLDER,
            src_path,
        ]
        res = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=60)

        # LibreOffice a veces escribe mensajes aunque convierta; validamos por existencia del PDF
        if os.path.isfile(out_pdf_path):
            return out_pdf_name

        # Si no creó el PDF, falló
        return None

    except Exception:
        return None
    
@app.route('/vista_evidencia/<path:filename>')
@login_required
def vista_evidencia(filename):
    ext = os.path.splitext(filename)[1].lower()
    is_pdf = ext == '.pdf'
    is_office = ext in {'.doc', '.docx', '.xls', '.xlsx'}

    # 1) Determinar a dónde volver (lee ?next=...)
    next_ep = request.args.get('next')  # p.ej. 'duenos_info', 'declaracion_aplicabilidad', etc.
    # Opcional: etiqueta de botón
    back_label_map = {
        'duenos_info': '⬅ Volver a Dueños de la Información',
        'declaracion_aplicabilidad': '⬅ Volver a SoA',
        'soa': '⬅ Volver a SoA',
        'activos_menu': '⬅ Volver a Gestión de Activos',
        'menu': '⬅ Volver al menú principal',
    }
    # Whitelist de endpoints permitidos a los que volver:
    allowed_back = set(back_label_map.keys())

    if next_ep in allowed_back:
        back_url = url_for(next_ep)
        back_label = back_label_map[next_ep]
    else:
        # fallback: intentar referrer o menú
        back_url = request.referrer or url_for('menu')
        back_label = '⬅ Volver'

    pdf_converted = None
    if is_office:
        # genera PDF si hace falta (asegúrate de tener CONVERTED_FOLDER y ensure_pdf_from_office)
        pdf_converted = ensure_pdf_from_office(filename)

    inner_html = """
    <div class="container my-3">
      <!-- Barra superior -->
      <div class="d-flex justify-content-between align-items-center mb-2">
        <a href="{{ back_url }}" class="btn btn-secondary rounded-pill px-4 py-2">
          {{ back_label }}
        </a>
        <div class="small text-muted text-truncate">Archivo: {{ filename }}</div>
      </div>

      <!-- Contenedor del visor -->
      <div class="card shadow-sm">
        <div class="card-body p-2">
          {% if is_pdf %}
            <div class="pdf-container">
              <iframe id="pdfFrame"
                      src="{{ url_for('ver_evidencia', filename=filename) }}#zoom=page-width"
                      title="Visor PDF"></iframe>
            </div>

          {% elif pdf_converted %}
            <div class="pdf-container">
              <iframe id="pdfFrame"
                      src="{{ url_for('ver_evidencia_convertido', filename=pdf_converted) }}#zoom=page-width"
                      title="Visor PDF (convertido)"></iframe>
            </div>
            <div class="mt-2 text-center">
              <a class="btn btn-outline-primary rounded-pill px-4"
                 href="{{ url_for('ver_evidencia', filename=filename) }}" target="_blank" rel="noopener">
                Abrir archivo original
              </a>
            </div>

          {% elif is_office %}
            <div class="alert alert-warning m-2">
              No fue posible generar una vista previa interna del archivo Office.
              Verifica que LibreOffice esté instalado en el servidor.
            </div>
            <div class="text-center mb-2">
              <a class="btn btn-outline-primary rounded-pill px-4"
                 href="{{ url_for('ver_evidencia', filename=filename) }}" target="_blank" rel="noopener">
                Abrir/descargar archivo original
              </a>
            </div>

          {% else %}
            <div class="alert alert-info m-2">
              Este tipo de archivo (<b>{{ ext }}</b>) no se puede previsualizar. Puedes abrirlo/descargarlo.
            </div>
            <div class="text-center mb-2">
              <a class="btn btn-outline-primary rounded-pill px-4"
                 href="{{ url_for('ver_evidencia', filename=filename) }}" target="_blank" rel="noopener">
                Abrir archivo
              </a>
            </div>
          {% endif %}
        </div>
      </div>
    </div>

    <style>
      /* Altura razonable dentro del layout, sin salirse */
      .pdf-container {
        height: min(82vh, 1000px);
        min-height: 600px;
        width: 100%;
      }
      .pdf-container iframe {
        width: 100%;
        height: 100%;
        border: 1px solid #dee2e6;
        border-radius: 8px;
        background: #fff;
      }
    </style>

    <script>
      function setZoom(z) {
        var f = document.getElementById('pdfFrame');
        if (!f) return;
        var base = f.src.split('#')[0];
        f.src = base + '#zoom=' + encodeURIComponent(z);
      }
    </script>
    <style>
          body {
            background-image: url('/static/img/ccsgsi.jpg'); /* Usa tu imagen */
            background-size: cover;       /* 🔹 ocupa toda la pantalla */
            background-position: center;  /* 🔹 centrada */
            background-attachment: fixed; /* 🔹 efecto de fondo fijo elegante */
            background-repeat: no-repeat;
          }

          /* Fondo suave en las tarjetas para que se lean bien */
          .card {
            background: rgba(255, 255, 255, 0.85) !important;
            backdrop-filter: blur(4px);
          }
        </style>
    """

    return render_template_string(
        BASE,
        content=Markup(render_template_string(
            inner_html,
            filename=filename,
            ext=ext,
            is_pdf=is_pdf,
            is_office=is_office,
            pdf_converted=pdf_converted,
            back_url=back_url,
            back_label=back_label
        ))
    )

