        r.estrategias_fa = request.form.get('estrategias_fa') or ""
        r.estrategias_do = request.form.get('estrategias_do') or ""
        r.estrategias_da = request.form.get('estrategias_da') or ""

        db.session.commit()
        flash("DOFA actualizado correctamente.", "success")
