def safe_str(x):
    """Convierte NaN/None a '' y todo lo demás a string limpio."""
    try:
        import pandas as pd
        if x is None:
            return ""
        # pandas NaN
        if isinstance(x, float) and x != x:
            return ""
        if "pd" in globals() and pd.isna(x):
            return ""
    except Exception:
        pass
    return str(x).replace("\ufeff", "").strip()

